const ce = Number(env.get('ce'));
const speed = Number(env.get('speed_hz'));
const mode = Number(env.get('spi_mode'));
const tx = env.get('tx_bytes');
const rxLen = Number(env.get('rx_length'));
const helperPath = env.get('helper_path');

if (!helperPath) { node.error('helper_path env var must be set', msg); return null; }
if (![0, 1].includes(ce)) { node.error('ce must be 0 or 1', msg); return null; }

msg._tx = tx;
msg.payload = `python3 ${helperPath} --ce ${ce} --speed ${speed} --mode ${mode} --tx '${tx}' --rx-length ${rxLen}`;
return msg;

const rc = msg.rc && typeof msg.rc.code === 'number' ? msg.rc.code : null;
const text = (typeof msg.payload === 'string') ? msg.payload : '';

if (rc === null) {
    msg._buf = (msg._buf || '') + text;
    return null;
}

const output = (msg._buf || '').trim();
try {
    const parsed = JSON.parse(output);
    parsed.tx = msg._tx;
    parsed.timestamp = new Date().toISOString();
    msg.payload = parsed;
} catch (e) {
    msg.payload = {
        success: false,
        error: `could not parse helper output: ${output}`,
        tx: msg._tx,
        exit_code: rc,
        timestamp: new Date().toISOString()
    };
}

delete msg._tx;
delete msg._buf;
return msg;
